test "expect State.backspace will reduce buffer_length by 1 when literal_index is not set" {
    // Arrange
    var state: State = undefined;
    state.init();

    // input 5 characters so that literal_index is not set.
    for ("bbbbb") |c| {
        state.add(c);
    }

    // Act
    state.backspace();

    // Assert
    try expectEqual(4, state.buffer_length);
    try expectEqual(null, state.buffer_modification_index);
    try expectEqual(null, state.literal_index);
}

test "expect State.calculate_synthetic_backspaces produces correct calculations" {
    // Arrange: no retroactive modification.
    var state: State = undefined;
    state.init();
    state.buffer_length = 3;
    state.buffer_length_previous = 3;
    state.buffer_modification_index = null;

    // Act + Assert: no modification means no synthetic backspaces.
    try expectEqual(0, state.calculate_synthetic_backspaces());

    // Arrange: modified the last visible span.
    state.init();
    state.buffer_length = 3;
    state.buffer_length_previous = 3;
    state.buffer_modification_index = 2;

    // Act + Assert: replace the suffix starting at index 2 of the previous buffer.
    try expectEqual(1, state.calculate_synthetic_backspaces());

    // Arrange: modified an earlier span, requires longer suffix replacement.
    state.init();
    state.buffer_length = 4;
    state.buffer_length_previous = 4;
    state.buffer_modification_index = 1;

    // Act + Assert: replace the suffix starting at index 1 of the previous buffer.
    try expectEqual(3, state.calculate_synthetic_backspaces());
}

test "expect State.calculate_synthetic_backspaces produces correct calculations in length-preserving retroactive edits" {
    // Arrange: "aa" applies circumflex on 'a' -> "â".
    var state: State = undefined;
    state.init();
    for ("aa") |c| {
        state.add(c);
    }
    try expectEqual(1, state.buffer_length_previous);
    try expectEqual(1, state.buffer_length);
    try expectEqual(0, state.buffer_modification_index);
    // Act + Assert
    try expectEqual(1, state.calculate_synthetic_backspaces());

    // Arrange: "aw" applies breve on 'a' -> "ă".
    state.init();
    for ("aw") |c| {
        state.add(c);
    }
    try expectEqual(1, state.buffer_length_previous);
    try expectEqual(1, state.buffer_length);
    try expectEqual(0, state.buffer_modification_index);
    // Act + Assert
    try expectEqual(1, state.calculate_synthetic_backspaces());

    // Arrange: "dd" applies stroke on 'd' -> "đ".
    state.init();
    for ("dd") |c| {
        state.add(c);
    }
    try expectEqual(1, state.buffer_length_previous);
    try expectEqual(1, state.buffer_length);
    try expectEqual(0, state.buffer_modification_index);
    // Act + Assert
    try expectEqual(1, state.calculate_synthetic_backspaces());

    // Arrange: "bans" applies rising tone on 'a' in "ban" -> "bán".
    state.init();
    for ("bans") |c| {
        state.add(c);
    }
    try expectEqual(3, state.buffer_length_previous);
    try expectEqual(3, state.buffer_length);
    try expectEqual(1, state.buffer_modification_index);
    // Act + Assert: suffix replacement count must be greater than 1.
    try expectEqual(2, state.calculate_synthetic_backspaces());
}

